external_knowledge:
- "Big spenders" refers to individuals with a total procurement cost of more than 1000; 
- "Environmentally friendly components" refers to components that are RoHS compliant; 
- "In bulk" refers to components with a stock level greater than 50.

sql:
SELECT SUM(quantity) AS total_quantity
FROM procurement
WHERE user_id = 1;

SELECT SUM(quantity) AS total_components
FROM shopping_cart
WHERE user_id = 1;
